/**
 * Workflow Event Outbox Model
 *
 * Transactional-outbox rows written inside the same Mongo session as the
 * workflow/human-task domain write. A background BullMQ poller reads
 * unpublished rows, publishes to Kafka via `publishAndAck`, and sets
 * `publishedAt` + `expiresAt` so the TTL index can reap published rows
 * without losing unpublished ones.
 *
 * The `_id` is the event_id (UUIDv7) generated by `buildOutboxPayload` and
 * MUST equal the Kafka event_id published downstream (dedup contract — the
 * CH consumer keys on `event_id` for idempotency).
 */

import mongoose, { Schema, type InferSchemaType } from 'mongoose';
import { tenantIsolationPlugin } from '../mongo/plugins/tenant-isolation.plugin.js';

const WorkflowEventOutboxSchema = new Schema(
  {
    _id: { type: String, required: true },
    tenantId: { type: String, required: true, index: true },
    projectId: { type: String, required: true },
    entityKind: {
      type: String,
      required: true,
      enum: ['workflow_execution', 'human_task'],
      index: true,
    },
    entityId: { type: String, required: true, index: true },
    topic: { type: String, required: true },
    eventType: { type: String, required: true },
    eventVersion: { type: String, required: true, default: '1.0.0' },
    occurredAt: { type: Date, required: true },
    payload: { type: Schema.Types.Mixed, required: true },
    publishedAt: { type: Date, default: null, index: true },
    lastError: { type: String, default: null },
    retryCount: { type: Number, default: 0 },
    expiresAt: { type: Date, default: null },
  },
  { timestamps: true, collection: 'workflow_event_outbox' },
);

// Poller hot-path index — "unpublished, oldest first"
WorkflowEventOutboxSchema.index(
  { occurredAt: 1 },
  { partialFilterExpression: { publishedAt: null } },
);

// TTL — only expires published rows (partial filter preserves unpublished
// indefinitely). Mongo rejects `$ne` in partial-filter expressions, so we
// filter on BSON type instead: published rows hold a Date, unpublished rows
// hold explicit `null`. `$type: 'date'` matches the former only.
WorkflowEventOutboxSchema.index(
  { expiresAt: 1 },
  { expireAfterSeconds: 0, partialFilterExpression: { publishedAt: { $type: 'date' } } },
);

// Per-entity ordering / dedup lookup.
WorkflowEventOutboxSchema.index({ tenantId: 1, entityKind: 1, entityId: 1, occurredAt: 1 });

WorkflowEventOutboxSchema.plugin(tenantIsolationPlugin);

export type WorkflowEventOutboxDoc = InferSchemaType<typeof WorkflowEventOutboxSchema>;

export const WorkflowEventOutboxModel =
  (mongoose.models.WorkflowEventOutbox as mongoose.Model<WorkflowEventOutboxDoc>) ??
  mongoose.model<WorkflowEventOutboxDoc>('WorkflowEventOutbox', WorkflowEventOutboxSchema);
